const response = items[0].json.output;

let data;
try {
    const jsonMatch = response.match(/\{[\s\S]*\}/);
    data = JSON.parse(jsonMatch[0]);
} catch (e) {
    return [{ json: { error: "JSON inválido", raw: response } }];
}

return [{
    json: {
        status:        data.status || data.cadastro_status || "",
        nome:          data.nome || "",
        email:         data.email || "",
        plano:         data.plano || "",
        telefone:      String(data.telefone || ""),
        data_cadastro: data.data_cadastro || data.datacadastro || ""
    }
}];

const output = $input.first().json.output;
const jsonMatch = output.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  return { json: { action: "nenhuma", output } };
}

const parsed = JSON.parse(jsonMatch[0]);

return {
  json: {
    action:        parsed.action || "nenhuma",
    event_id:      parsed.event_id || "",
    telefone:      parsed.telefone || "",
    data_consulta: parsed.data_consulta || "",
    nome_paciente: parsed.nome_paciente || "",
    valor:         parsed.valor || "",
    pagamento_status: parsed.pagamento_status || "pendente",
    email_paciente: parsed.email_paciente || ""
  }
};

// Pega o que a IA escreveu
const output = $input.first().json.output || "";

// Tenta achar o JSON no meio do texto
const jsonMatch = output.match(/\{[\s\S]*\}/);
let parsed = {};

if (jsonMatch) {
    try {
        parsed = JSON.parse(jsonMatch[0]);
    } catch (e) {
        // Se der erro no parse, mantemos o objeto vazio
    }
}

// Retorna exatamente o que o nó de "Append or Update" precisa
return {
  json: {
    event_id: parsed.event_id || "",
    // Aqui usamos a referência direta do input do nó, que é mais seguro
    row_number: $input.first().json.row_number || ""
  }
};

const hoje = new Date();
hoje.setHours(12, 0, 0, 0);

const telefonesComConsulta = new Set(
  $input.all()
    .filter(i => i.json.data_consulta)
    .map(i => String(i.json.telefone))
);

const pacientesParaLembrar = [];

for (const item of $input.all()) {
  const p = item.json;
  if (!p.ultima_consulta || !p.telefone || !p.nome) continue;
  if (telefonesComConsulta.has(String(p.telefone))) continue;

  const [dia, mes, ano] = p.ultima_consulta.split('/');
  const dataConsulta = new Date(parseInt(ano), parseInt(mes) - 1, parseInt(dia), 12, 0, 0);
  const diasPassados = Math.floor((hoje - dataConsulta) / (1000 * 60 * 60 * 24));

  if (diasPassados === 30) {
    pacientesParaLembrar.push({
      json: {
        telefone: p.telefone,
        nome: p.nome,
        dias: diasPassados
      }
    });
  }
}

return pacientesParaLembrar;

let total = 0;

for (const item of $input.all()) {
  const v = parseFloat(item.json.valor);
  if (!isNaN(v)) total += v;
}

return [{
  json: {
    descricao: "expectativa_pagamento",
    valor: total
  }
}];
